export type ResourceId = string & { readonly __brand: "ResourceId" };
export type EdgeId = string & { readonly __brand: "EdgeId" };
export type JobId = string & { readonly __brand: "JobId" };

export type NodeType = "container" | "database" | "devEnv" | "entry";
export type EdgeKind = "depends-on" | "connects-to" | "routes-to";

export interface NodeRef {
  id: ResourceId;
  position: { x: number; y: number };
  type: NodeType;
}

export interface EdgeRef {
  id: EdgeId;
  kind: EdgeKind;
  source: ResourceId;
  target: ResourceId;
}

import type { EdgeRef, JobId, NodeRef } from "./resource-types";

export interface CanvasNode extends NodeRef {
  ghostJobId?: JobId;
  isGhost?: boolean;
}

export type CanvasEdge = EdgeRef;

export interface CanvasState {
  projectId: string;
}

export interface CanvasActions {
  fitView: () => void;
}

export type CanvasMeta = Record<string, never>;

export interface CanvasContextValue {
  actions: CanvasActions;
  meta: CanvasMeta;
  state: CanvasState;
}

import type { CanvasNode } from "./types";

export function isContainerNode(node: CanvasNode) {
  return node.type === "container";
}

export function isDatabaseNode(node: CanvasNode) {
  return node.type === "database";
}

export function isDevEnvNode(node: CanvasNode) {
  return node.type === "devEnv";
}

export function isEntryNode(node: CanvasNode) {
  return node.type === "entry";
}

export function isGhostNode(node: CanvasNode) {
  return node.isGhost === true;
}

import { createContext } from "react";
import type { CanvasContextValue } from "./types";

export const CanvasContext = createContext<CanvasContextValue | null>(null);

import { atom } from "jotai";
import { atomFamily } from "jotai/utils";
import type { EdgeId, JobId, NodeType, ResourceId } from "./resource-types";

export interface ViewportState {
  x: number;
  y: number;
  zoom: number;
}

export const viewportAtom = atom<ViewportState>({ x: 0, y: 0, zoom: 1 });

export const expandedNodesAtomFamily = atomFamily((_id: ResourceId) =>
  atom(false)
);

export const activeEdgeAtom = atom<EdgeId | null>(null);

export interface GhostNode {
  id: `ghost:${JobId}`;
  jobId: JobId;
  position: { x: number; y: number };
  type: NodeType;
}

export const ghostNodesAtomFamily = atomFamily((_projectId: string) =>
  atom<GhostNode[]>([])
);

export const focusedNodeAtom = atom<{
  id: ResourceId;
  expand?: boolean;
} | null>(null);

"use client";

import { use } from "react";
import { CanvasContext } from "./canvas-context";

export function useCanvas() {
  const ctx = use(CanvasContext);
  if (!ctx) {
    throw new Error("useCanvas must be used inside CanvasProvider");
  }
  return ctx;
}

"use client";

import { useReactFlow } from "@xyflow/react";
import { type ReactNode, useCallback, useMemo } from "react";
import { CanvasContext } from "./canvas-context";
import type { CanvasContextValue } from "./types";

export function CanvasProvider({
  children,
  projectId,
}: {
  children: ReactNode;
  projectId: string;
}) {
  const { fitView } = useReactFlow();

  const fitViewAction = useCallback(() => {
    fitView();
  }, [fitView]);

  const value = useMemo<CanvasContextValue>(
    () => ({
      state: { projectId },
      actions: { fitView: fitViewAction },
      meta: {},
    }),
    [projectId, fitViewAction]
  );

  return <CanvasContext value={value}>{children}</CanvasContext>;
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import { Button } from "../button";

export function CanvasErrorFallback({
  error,
  reset,
  className,
}: {
  error: Error & { digest?: string };
  reset: () => void;
  /** Merged with default layout; omit for full-viewport route errors. */
  className?: string;
}) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-4 p-6 text-center",
        className ?? "h-dvh"
      )}
    >
      <h1 className="font-medium text-lg">Canvas failed to load</h1>
      <p className="max-w-md text-muted-foreground text-sm">{error.message}</p>
      <Button onClick={reset}>Try again</Button>
    </div>
  );
}

.canvas-surface {
  position: absolute;
  inset: 0;
  overflow: hidden;
  background-color: var(--color-canvas-surface);
  background-image: radial-gradient(
    ellipse 83.7% 93.3% at 33% 53%,
    color-mix(in oklab, var(--color-canvas-glow) 22%, transparent) 0%,
    transparent 70%
  );
}

.canvas-surface > .react-flow {
  width: 100%;
  height: 100%;
  background: transparent;
}

.react-flow__pane.draggable,
.react-flow__pane.dragging {
  cursor: default;
}

"use client";

import "@xyflow/react/dist/base.css";
import "@xyflow/react/dist/style.css";
import "./canvas.css";

import {
  Background,
  BackgroundVariant,
  ReactFlow,
  ReactFlowProvider,
} from "@xyflow/react";
import { Provider as JotaiProvider } from "jotai";
import { CanvasProvider } from "./canvas-provider";

export function Canvas({ projectId }: { projectId: string }) {
  return (
    <div className="h-full min-h-0 w-full min-w-0">
      <JotaiProvider>
        <ReactFlowProvider>
          <CanvasProvider projectId={projectId}>
            <div className="relative h-full min-h-0 w-full min-w-0">
              <div className="canvas-surface">
                <ReactFlow
                  edges={[]}
                  fitView
                  nodes={[]}
                  proOptions={{ hideAttribution: true }}
                >
                  <Background
                    color="var(--color-canvas-dot)"
                    gap={[32, 41]}
                    size={1}
                    variant={BackgroundVariant.Dots}
                  />
                </ReactFlow>
              </div>
            </div>
          </CanvasProvider>
        </ReactFlowProvider>
      </JotaiProvider>
    </div>
  );
}
